diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 9f034aba874a..cc3e4b59ea35 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -3344,6 +3344,65 @@ Instruction *InstCombinerImpl::foldICmpBinOpEqualityWithConstant(
         Neg->takeName(BO);
         return new ICmpInst(Pred, BOp0, Neg);
       }
+    } else {
+      // icmp eq/ne (add (zext/sext i1 X), (zext/sext i1 Y)), C
+      // where C is in {-2, -1, 0, 1, 2}.
+      // zext(X) is 0 or 1, sext(X) is 0 or -1.
+      Value *X, *Y;
+      if (match(BOp0, m_ZExtOrSExt(m_Value(X))) &&
+          match(BOp1, m_ZExtOrSExt(m_Value(Y))) &&
+          X->getType()->isIntOrIntVectorTy(1) &&
+          Y->getType()->isIntOrIntVectorTy(1)) {
+        auto *BO0 = cast<Instruction>(BOp0);
+        auto *BO1 = cast<Instruction>(BOp1);
+        bool IsZExt0 = BO0->getOpcode() == Instruction::ZExt;
+        bool IsZExt1 = BO1->getOpcode() == Instruction::ZExt;
+        Value *Result = nullptr;
+
+        if (IsZExt0 && IsZExt1) {
+          // zext + zext: possible sums are 0, 1, 2
+          if (C.isZero())
+            // 0: both zero -> !X && !Y = not (X or Y)
+            Result = Builder.CreateNot(Builder.CreateOr(X, Y));
+          else if (C.isOne())
+            // 1: one is one -> X xor Y
+            Result = Builder.CreateXor(X, Y);
+          else if (C == 2)
+            // 2: both one -> X and Y
+            Result = Builder.CreateAnd(X, Y);
+        } else if (!IsZExt0 && !IsZExt1) {
+          // sext + sext: possible sums are 0, -1, -2
+          if (C.isZero())
+            // 0: both zero -> !X && !Y = not (X or Y)
+            Result = Builder.CreateNot(Builder.CreateOr(X, Y));
+          else if (C.isAllOnes())
+            // -1: one is -1 -> X xor Y
+            Result = Builder.CreateXor(X, Y);
+          else if (C == -2)
+            // -2: both -1 -> X and Y
+            Result = Builder.CreateAnd(X, Y);
+        } else {
+          // sext + zext (commutative): possible sums are -1, 0, 1
+          // Let Z be the zext operand (0 or 1), S be the sext operand (0 or -1)
+          Value *ZExtSrc = IsZExt0 ? X : Y;
+          Value *SExtSrc = IsZExt0 ? Y : X;
+          if (C.isZero())
+            // 0: both zero or both non-zero -> X == Y = not (xor X, Y)
+            Result = Builder.CreateNot(Builder.CreateXor(X, Y));
+          else if (C.isOne())
+            // 1: sext=0, zext=1 -> !SExtSrc && ZExtSrc
+            Result = Builder.CreateAnd(Builder.CreateNot(SExtSrc), ZExtSrc);
+          else if (C.isAllOnes())
+            // -1: sext=-1, zext=0 -> SExtSrc && !ZExtSrc
+            Result = Builder.CreateAnd(SExtSrc, Builder.CreateNot(ZExtSrc));
+        }
+
+        if (Result) {
+          if (Pred == ICmpInst::ICMP_NE)
+            Result = Builder.CreateNot(Result);
+          return replaceInstUsesWith(Cmp, Result);
+        }
+      }
     }
     break;
   }

